Below is a complete Golang CLI tool that calculates the total size of all files in a given directory (including subdirectories) while allowing users to exclude specific file types or directories. The size is displayed in a human-readable format (bytes, KB, MB, GB, TB).

---

## Code Explanation

1. **Command-line parsing** – The `flag` package is used to define the required directory argument and optional flags for excluding files (`-exclude`) and directories (`-exclude-dir`). Patterns are provided as glob strings (e.g., `*.txt`, `.git`).

2. **Directory traversal** – `filepath.Walk` recursively visits every file and directory. For each entry:
   - If it is a directory, check if it matches any excluded directory pattern. If it does, skip it and its contents.
   - If it is a file, check if it matches any excluded file pattern. If it does, skip it.
   - Otherwise, add the file’s size to the total.

3. **Human-readable formatting** – The `formatSize` function converts the total bytes into a string with appropriate units (B, KB, MB, GB, TB).

4. **Error handling** – If the directory does not exist or is not accessible, an error message is printed and the program exits.

---

## Full Code

```go
package main

import (
	"flag"
	"fmt"
	"os"
	"path/filepath"
	"regexp"
	"strings"
)

func formatSize(size int64) string {
	const (
		KB = 1024
		MB = 1024 * KB
		GB = 1024 * MB
		TB = 1024 * GB
	)
	var unit string
	switch {
	case size >= TB:
		unit = "TB"
		size /= TB
	case size >= GB:
		unit = "GB"
		size /= GB
	case size >= MB:
		unit = "MB"
		size /= MB
	case size >= KB:
		unit = "KB"
		size /= KB
	default:
		return fmt.Sprintf("%d B", size)
	}
	return fmt.Sprintf("%d %s", size, unit)
}

func main() {
	dir := flag.String("dir", "", "Directory path to calculate size for")
	excludeFiles := flag.String("exclude", "", "Comma-separated list of file patterns to exclude (e.g., *.txt, *.log)")
	excludeDirs := flag.String("exclude-dir", "", "Comma-separated list of directory names to exclude (e.g., .git, node_modules)")
	flag.Parse()

	if *dir == "" {
		fmt.Println("Usage: disk_usage [-dir PATH] [-exclude FILES] [-exclude-dir DIRS]")
		fmt.Println("  -dir PATH          Directory to analyze (required)")
		fmt.Println("  -exclude FILES     File patterns to skip (glob, e.g., *.txt)")
		fmt.Println("  -exclude-dir DIRS  Directory names to skip (e.g., .git, tmp)")
		os.Exit(1)
	}

	// Validate directory
	info, err := os.Stat(*dir)
	if err != nil {
		fmt.Printf("Error: cannot access directory '%s': %v\n", *dir, err)
		os.Exit(1)
	}
	if !info.IsDir() {
		fmt.Printf("Error: '%s' is not a directory\n", *dir)
		os.Exit(1)
	}

	// Parse exclude patterns
	var filePatterns, dirPatterns []string
	if *excludeFiles != "" {
		filePatterns = strings.Split(*excludeFiles, ",")
	}
	if *excludeDirs != "" {
		dirPatterns = strings.Split(*excludeDirs, ",")
	}

	// Compile regex for file patterns (glob to regex)
	var fileRegexes []*regexp.Regexp
	for _, pattern := range filePatterns {
		regex, err := filepath.ToSlash(pattern)
		if err != nil {
			fmt.Printf("Warning: invalid file pattern '%s': %v\n", pattern, err)
			continue
		}
		regex = regexp.QuoteMeta(regex)
		// Convert glob pattern to regex: * -> .*
		regex = strings.ReplaceAll(regex, `\*`, `.*`)
		fileRegexes = append(fileRegexes, regexp.MustCompile(`^` + regex + `$`))
	}

	// Compile regex for directory patterns
	var dirRegexes []*regexp.Regexp
	for _, pattern := range dirPatterns {
		regex, err := filepath.ToSlash(pattern)
		if err != nil {
			fmt.Printf("Warning: invalid directory pattern '%s': %v\n", pattern, err)
			continue
		}
		regex = regexp.QuoteMeta(regex)
		regex = strings.ReplaceAll(regex, `\*`, `.*`)
		dirRegexes = append(dirRegexes, regexp.MustCompile(`^` + regex + `$`))
	}

	// Traverse directory
	var totalSize int64
	err = filepath.Walk(*dir, func(path string, info os.FileInfo, err error) error {
		if err != nil {
			fmt.Printf("Warning: skipping '%s': %v\n", path, err)
			return nil
		}

		// Skip excluded directories
		if info.IsDir() {
			for _, re := range dirRegexes {
				if re.MatchString(info.Name()) {
					fmt.Printf("Skipping directory: %s\n", path)
					return filepath.SkipDir // skip entire subtree
				}
			}
		}

		// Skip excluded files
		if !info.IsDir() {
			for _, re := range fileRegexes {
				if re.MatchString(info.Name()) {
					fmt.Printf("Skipping file: %s\n", path)
					return nil
				}
			}
		}

		// Add file size
		if !info.IsDir() {
			totalSize += info.Size()
		}
		return nil
	})

	if err != nil {
		fmt.Printf("Error during walk: %v\n", err)
		os.Exit(1)
	}

	fmt.Printf("Total size: %s\n", formatSize(totalSize))
}
```

